// src/components/Hero.jsx
import { useEffect, useRef } from 'react';
import { personal } from '../data/portfolio';

function ParticleCanvas() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;
    let mouse = { x: null, y: null };

    const resize = () => {
      canvas.width  = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
    };
    resize();
    window.addEventListener('resize', resize);

    const PARTICLE_COUNT = 90;
    const CONNECTION_DIST = 140;
    const MOUSE_DIST = 160;

    const particles = Array.from({ length: PARTICLE_COUNT }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      r: Math.random() * 2 + 1,
    }));

    const onMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
    };
    const onLeave = () => { mouse.x = null; mouse.y = null; };
    canvas.addEventListener('mousemove', onMove);
    canvas.addEventListener('mouseleave', onLeave);

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Mover partículas
      particles.forEach(p => {
        // Atracción suave al ratón
        if (mouse.x !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < MOUSE_DIST) {
            p.vx += dx / dist * 0.06;
            p.vy += dy / dist * 0.06;
          }
        }

        // Límite de velocidad
        const speed = Math.sqrt(p.vx * p.vx + p.vy * p.vy);
        if (speed > 1.8) { p.vx = (p.vx / speed) * 1.8; p.vy = (p.vy / speed) * 1.8; }

        p.x += p.vx;
        p.y += p.vy;

        // Rebote en bordes
        if (p.x < 0 || p.x > canvas.width)  p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        // Dibujar punto
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(232,58,58,0.7)';
        ctx.fill();
      });

      // Dibujar líneas entre partículas cercanas
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < CONNECTION_DIST) {
            const alpha = (1 - dist / CONNECTION_DIST) * 0.25;
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(232,58,58,${alpha})`;
            ctx.lineWidth = 0.8;
            ctx.stroke();
          }
        }
        // Línea desde ratón a partículas cercanas
        if (mouse.x !== null) {
          const dx = particles[i].x - mouse.x;
          const dy = particles[i].y - mouse.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < MOUSE_DIST) {
            const alpha = (1 - dist / MOUSE_DIST) * 0.5;
            ctx.beginPath();
            ctx.moveTo(mouse.x, mouse.y);
            ctx.lineTo(particles[i].x, particles[i].y);
            ctx.strokeStyle = `rgba(232,58,58,${alpha})`;
            ctx.lineWidth = 0.8;
            ctx.stroke();
          }
        }
      }

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
      canvas.removeEventListener('mousemove', onMove);
      canvas.removeEventListener('mouseleave', onLeave);
    };
  }, []);

  return <canvas ref={canvasRef} style={s.canvas} />;
}

export default function Hero() {
  return (
    <section id="hero" style={s.section}>
      {/* Canvas de partículas */}
      <ParticleCanvas />

      {/* Overlay oscuro */}
      <div style={s.overlay} />

      {/* Contenido */}
      <div style={s.content}>
        <div style={s.badge}>
          <span style={s.badgeDot} />
          Disponible para trabajar
        </div>

        <p style={s.greeting}>Hola, soy</p>

        <h1 style={s.name}>
          {personal.name.split(' ')[0]}<br />
          <span style={s.nameAccent}>{personal.name.split(' ')[1]}</span>
        </h1>

        <p style={s.role}>{personal.role}</p>
        <p style={s.tagline}>{personal.tagline}</p>

        <p style={s.desc}>
          Desarrollador Web proactivo con experiencia práctica en aplicaciones Full Stack
          en entornos reales. Especializado en{' '}
          <strong style={s.strong}>React</strong>,{' '}
          <strong style={s.strong}>.NET</strong> y{' '}
          <strong style={s.strong}>SQL</strong>.
          Alta capacidad de adaptación y aprendizaje rápido.
        </p>

        <div style={s.actions}>
          <a
            href="#contact"
            style={s.btnPrimary}
            onMouseEnter={e => { e.currentTarget.style.background = 'var(--accent2)'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
            onMouseLeave={e => { e.currentTarget.style.background = 'var(--accent)'; e.currentTarget.style.transform = 'none'; }}
          >
            Contactar
          </a>
          <a
            href="#experience"
            style={s.btnSecondary}
            onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.3)'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.15)'; e.currentTarget.style.transform = 'none'; }}
          >
            Ver mi trabajo ↓
          </a>
        </div>

        <div style={s.stats}>
          {personal.stats.map((st, i) => (
            <div key={i}>
              <div style={s.statNum}>
                {st.value.replace(/[^0-9A-Za-z]/g, '')}
                <span style={s.statAccent}>{st.value.match(/[^0-9A-Za-z]/)?.[0] || ''}</span>
              </div>
              <div style={s.statLabel}>{st.label}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

const s = {
  section: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    padding: '120px 5% 80px',
    position: 'relative',
    overflow: 'hidden',
    background: '#0c0c0e',
  },
  canvas: {
    position: 'absolute',
    inset: 0,
    width: '100%',
    height: '100%',
    zIndex: 0,
  },
  overlay: {
    position: 'absolute',
    inset: 0,
    background: 'linear-gradient(to right, rgba(10,10,12,0.92) 40%, rgba(10,10,12,0.6) 100%)',
    zIndex: 1,
    pointerEvents: 'none',
  },
  content: {
    position: 'relative',
    zIndex: 2,
    maxWidth: 640,
  },
  badge: {
    display: 'inline-flex', alignItems: 'center', gap: 8,
    background: 'rgba(232,58,58,0.09)',
    border: '1px solid rgba(232,58,58,0.22)',
    color: 'var(--accent2)',
    fontSize: 11, fontWeight: 600,
    letterSpacing: '0.12em', textTransform: 'uppercase',
    padding: '6px 16px', borderRadius: 100,
    marginBottom: 32,
  },
  badgeDot: {
    display: 'inline-block', width: 6, height: 6,
    borderRadius: '50%', background: 'var(--accent)',
    animation: 'pulse 2s infinite',
  },
  greeting: {
    fontFamily: 'var(--font-body)', fontSize: 20,
    fontWeight: 300, color: 'var(--text2)', marginBottom: 6,
  },
  name: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(56px, 8vw, 92px)',
    fontWeight: 800, letterSpacing: '-3px',
    lineHeight: 1, color: 'var(--text)', marginBottom: 16,
  },
  nameAccent: { color: 'var(--accent)' },
  role: {
    fontFamily: 'var(--font-head)',
